import{_ as a,c as t,o as i,a1 as n}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Advanced: Multi-Account & Rate Limits | opencode-antigravity-auth","description":"Master advanced features including multi-account load balancing, intelligent account selection, rate limit handling, and session recovery mechanisms for optimal performance.","frontmatter":{"title":"Advanced: Multi-Account & Rate Limits | opencode-antigravity-auth","sidebarTitle":"Advanced","subtitle":"Advanced Features","description":"Master advanced features including multi-account load balancing, intelligent account selection, rate limit handling, and session recovery mechanisms for optimal performance.","order":3},"headers":[],"relativePath":"NoeFabris/opencode-antigravity-auth/advanced/index.md","filePath":"NoeFabris/opencode-antigravity-auth/advanced/index.md"}'),o={name:"NoeFabris/opencode-antigravity-auth/advanced/index.md"};function r(l,e,s,c,u,d){return i(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="advanced-features" tabindex="-1">Advanced Features <a class="header-anchor" href="#advanced-features" aria-label="Permalink to &quot;Advanced Features&quot;">​</a></h1><p>This section helps you deeply master the advanced features of the Antigravity Auth plugin, including multi-account load balancing, intelligent account selection, rate limit handling, session recovery, request transformation, and other core mechanisms. Whether optimizing quota utilization or troubleshooting complex issues, you&#39;ll find the answers you need here.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Before You Begin</p><ul><li>✅ Completed <a href="./../start/quick-install/">Quick Installation</a> and successfully added the first account</li><li>✅ Completed <a href="./../start/first-auth-login/">First Authentication</a> and understand the OAuth flow</li><li>✅ Completed <a href="./../start/first-request/">First Request</a> and verified the plugin is working correctly</li></ul></div><h2 id="learning-path" tabindex="-1">Learning Path <a class="header-anchor" href="#learning-path" aria-label="Permalink to &quot;Learning Path&quot;">​</a></h2><h3 id="_1-multi-account-setup" tabindex="-1">1. <a href="./multi-account-setup/">Multi-Account Setup</a> <a class="header-anchor" href="#_1-multi-account-setup" aria-label="Permalink to &quot;1. [Multi-Account Setup](./multi-account-setup/)&quot;">​</a></h3><p>Configure multiple Google accounts to implement quota pooling and load balancing.</p><ul><li>Add multiple accounts to increase overall quota limits</li><li>Understand the dual quota system (Antigravity + Gemini CLI)</li><li>Choose the appropriate number of accounts based on your scenario</li></ul><h3 id="_2-account-selection-strategies" tabindex="-1">2. <a href="./account-selection-strategies/">Account Selection Strategies</a> <a class="header-anchor" href="#_2-account-selection-strategies" aria-label="Permalink to &quot;2. [Account Selection Strategies](./account-selection-strategies/)&quot;">​</a></h3><p>Master best practices for sticky, round-robin, and hybrid account selection strategies.</p><ul><li>1 account → sticky strategy preserves prompt cache</li><li>2-3 accounts → hybrid strategy intelligently distributes requests</li><li>4+ accounts → round-robin strategy maximizes throughput</li></ul><h3 id="_3-rate-limit-handling" tabindex="-1">3. <a href="./rate-limit-handling/">Rate Limit Handling</a> <a class="header-anchor" href="#_3-rate-limit-handling" aria-label="Permalink to &quot;3. [Rate Limit Handling](./rate-limit-handling/)&quot;">​</a></h3><p>Understand rate limit detection, automatic retry, and account switching mechanisms.</p><ul><li>Distinguish between 5 different types of 429 errors</li><li>Understand the exponential backoff algorithm for automatic retries</li><li>Master automatic switching logic in multi-account scenarios</li></ul><h3 id="_4-session-recovery" tabindex="-1">4. <a href="./session-recovery/">Session Recovery</a> <a class="header-anchor" href="#_4-session-recovery" aria-label="Permalink to &quot;4. [Session Recovery](./session-recovery/)&quot;">​</a></h3><p>Learn about session recovery mechanisms to automatically handle tool call failures and interruptions.</p><ul><li>Automatically handle tool_result_missing errors</li><li>Fix thinking_block_order issues</li><li>Configure auto_resume and session_recovery options</li></ul><h3 id="_5-request-transformation-mechanism" tabindex="-1">5. <a href="./request-transformation/">Request Transformation Mechanism</a> <a class="header-anchor" href="#_5-request-transformation-mechanism" aria-label="Permalink to &quot;5. [Request Transformation Mechanism](./request-transformation/)&quot;">​</a></h3><p>Gain a deep understanding of request transformation mechanisms and how to handle protocol differences between different AI models.</p><ul><li>Understand protocol differences between Claude and Gemini models</li><li>Troubleshoot 400 errors caused by Schema incompatibilities</li><li>Optimize Thinking configuration for best performance</li></ul><h3 id="_6-configuration-guide" tabindex="-1">6. <a href="./configuration-guide/">Configuration Guide</a> <a class="header-anchor" href="#_6-configuration-guide" aria-label="Permalink to &quot;6. [Configuration Guide](./configuration-guide/)&quot;">​</a></h3><p>Master all configuration options to customize plugin behavior as needed.</p><ul><li>Configuration file locations and priorities</li><li>Model behavior, account rotation, and application behavior settings</li><li>Recommended configurations for single-account/multi-account/parallel agent scenarios</li></ul><h3 id="_7-parallel-agents-optimization" tabindex="-1">7. <a href="./parallel-agents/">Parallel Agents Optimization</a> <a class="header-anchor" href="#_7-parallel-agents-optimization" aria-label="Permalink to &quot;7. [Parallel Agents Optimization](./parallel-agents/)&quot;">​</a></h3><p>Optimize account allocation for parallel agent scenarios by enabling PID offset.</p><ul><li>Understand account conflicts in parallel agent scenarios</li><li>Enable PID offset so different processes prioritize different accounts</li><li>Coordinate with round-robin strategy to maximize multi-account utilization</li></ul><h3 id="_8-debug-logging" tabindex="-1">8. <a href="./debug-logging/">Debug Logging</a> <a class="header-anchor" href="#_8-debug-logging" aria-label="Permalink to &quot;8. [Debug Logging](./debug-logging/)&quot;">​</a></h3><p>Enable debug logging to troubleshoot issues and monitor runtime status.</p><ul><li>Enable debug logging to record detailed information</li><li>Understand different log levels and applicable scenarios</li><li>Interpret log content to quickly locate problems</li></ul><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to &quot;Next Steps&quot;">​</a></h2><p>After completing advanced features learning, you can:</p><ul><li>📖 Check <a href="./../faq/">Frequently Asked Questions</a> to resolve issues encountered during usage</li><li>📚 Read <a href="./../appendix/">Appendix</a> to understand architecture design and complete configuration reference</li><li>🔄 Follow <a href="./../changelog/">Changelog</a> to get the latest features and changes</li></ul>',32)])])}const m=a(o,[["render",r]]);export{g as __pageData,m as default};
